from cryptography.fernet import Fernet
from django.conf import settings

class MasterKeyManager:
    @staticmethod
    def get_master_key():
        return settings.MASTER_KEY

    @staticmethod
    def encrypt(key):
        fernet = Fernet(MasterKeyManager.get_master_key())
        return fernet.encrypt(key)

    @staticmethod
    def decrypt(encrypted_key):
        fernet = Fernet(MasterKeyManager.get_master_key())
        return fernet.decrypt(encrypted_key)
```

Now, for our `EncryptionManager` class, it's just a matter of taking that encrypted byte array and giving it to the `MasterKeyManager` to do its thing:

```python
