Oh boy, you want me to write an optimal C++ code for symbolic differentiation? Well, let's put on our best game faces because this is going to be a real beauty. 

First off, we're gonna need a few libraries. You know, the usual suspects: `iostream` for input/output, `string` for handling our functions, and `map` from `<unordered_map>` for storing variables and their coefficients. We might also need `sstream` for string stream operations.

```cpp
#include <iostream>
#include <string>
#include <unordered_map>
#include <sstream>

using namespace std;

class SymbolicDifferentiator {
private:
    unordered_map<string, int> variables; // Stores variable names and their coefficients

public:
    void addTerm(const string& term) {
        istringstream iss(term);
        string variable;
        int coefficient = 1;

        // Handle positive or negative coefficients
        if (term[0] == '-' || term[0] == '+') {
            iss >> term;
        }

        // Check for coefficient
        if (term.find('*') != string::npos) {
            iss >> variable >> coefficient;
        } else {
            iss >> variable;
        }

        // Increment the exponent by 1 and update the coefficient
        auto it = variables.find(variable);
        if (it != variables.end()) {
            it->second.first *= it->second.second + 1;
            it->second.second = 0; // Reset the exponent
        } else {
            variables[variable] = {coefficient, 1}; // New variable
        }
    }

    string differentiate() {
        stringstream result;
        for (auto& var : variables) {
            if (var.second.second > 0) {
                result << var.second.first * var.second.second << "*" << var.first << "^" << var.second.second - 1;
                var.second.second--; // Decrease the exponent
            }
        }
        return result.str();
    }

    void parseFunction(const string& function) {
        istringstream iss(function);
        string term;
        while (getline(iss, term, '+')) {
            addTerm(term);
        }
    }
};

int main() {
